import{_ as i,C as o,o as t,c as s,a2 as a,b as d,w as n,a as l,E as c,a3 as h}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"OpenHands — Benchmark Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/openhands/benchmarks.md","filePath":"research/agents/openhands/benchmarks.md"}'),p={name:"research/agents/openhands/benchmarks.md"};function m(u,e,g,b,f,k){const r=o("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a(`<h1 id="openhands-—-benchmark-analysis" tabindex="-1">OpenHands — Benchmark Analysis <a class="header-anchor" href="#openhands-—-benchmark-analysis" aria-label="Permalink to &quot;OpenHands — Benchmark Analysis&quot;">​</a></h1><blockquote><p><strong>Headline metric</strong>: 77.6% on SWE-bench Verified (best-in-class among open-source agents)</p></blockquote><p>OpenHands maintains one of the most rigorous open-source evaluation infrastructures in the AI coding-agent space. This document covers their performance across benchmarks, methodology, historical trajectory, and competitive positioning.</p><hr><h2 id="_1-swe-bench-verified" tabindex="-1">1. SWE-bench Verified <a class="header-anchor" href="#_1-swe-bench-verified" aria-label="Permalink to &quot;1. SWE-bench Verified&quot;">​</a></h2><p>SWE-bench is the de-facto standard for evaluating AI coding agents. It tests an agent&#39;s ability to resolve <strong>real-world GitHub issues</strong> — locating buggy code, understanding context, and producing correct patches in Python repositories.</p><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td><strong>Score</strong></td><td>77.6%</td></tr><tr><td><strong>Benchmark variant</strong></td><td>SWE-bench Verified</td></tr><tr><td><strong>Best model</strong></td><td>Claude (Anthropic)</td></tr><tr><td><strong>Evaluation repo</strong></td><td><a href="https://github.com/OpenHands/benchmarks" target="_blank" rel="noreferrer">github.com/OpenHands/benchmarks</a></td></tr><tr><td><strong>Results tracking</strong></td><td>Google Sheets (linked from README badge)</td></tr></tbody></table><h3 id="what-swe-bench-verified-tests" tabindex="-1">What SWE-bench Verified tests <a class="header-anchor" href="#what-swe-bench-verified-tests" aria-label="Permalink to &quot;What SWE-bench Verified tests&quot;">​</a></h3><ul><li>Each instance is a real GitHub issue + the gold-standard patch that resolved it.</li><li>The agent receives the issue text and repository state, then must produce a diff.</li><li>&quot;Verified&quot; is the human-validated subset — harder and more reliable than Lite/Full.</li><li>Tests span popular Python projects (Django, scikit-learn, sympy, flask, etc.).</li></ul><h3 id="performance-across-llms" tabindex="-1">Performance across LLMs <a class="header-anchor" href="#performance-across-llms" aria-label="Permalink to &quot;Performance across LLMs&quot;">​</a></h3><p>OpenHands performance is heavily model-dependent. The 77.6% headline reflects the best underlying LLM (Claude). Other models yield meaningfully different results:</p><table tabindex="0"><thead><tr><th>Underlying LLM</th><th>Approx. SWE-bench Verified</th><th>Notes</th></tr></thead><tbody><tr><td>Claude 3.5/4 Sonnet</td><td><strong>77.6%</strong></td><td>Headline score</td></tr><tr><td>GPT-4o / GPT-4.1</td><td>~55–65%</td><td>Strong but below Claude</td></tr><tr><td>Open-weight models</td><td>~30–45%</td><td>Llama, DeepSeek, etc.</td></tr></tbody></table><blockquote><p><strong>Key insight</strong>: The agent framework matters, but the LLM is the dominant variable. OpenHands&#39;s CodeAct architecture is optimized to extract maximum performance from frontier models.</p></blockquote><hr><h2 id="_2-terminal-bench-2-0" tabindex="-1">2. Terminal-Bench 2.0 <a class="header-anchor" href="#_2-terminal-bench-2-0" aria-label="Permalink to &quot;2. Terminal-Bench 2.0&quot;">​</a></h2><p>Terminal-Bench evaluates agents on CLI/terminal interaction tasks — file manipulation, system administration, development workflows, and shell scripting.</p><h3 id="openhands-results-on-terminal-bench-2-0" tabindex="-1">OpenHands results on Terminal-Bench 2.0 <a class="header-anchor" href="#openhands-results-on-terminal-bench-2-0" aria-label="Permalink to &quot;OpenHands results on Terminal-Bench 2.0&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Agent + Model</th><th>Score</th></tr></thead><tbody><tr><td><strong>#49</strong></td><td>OpenHands + Claude Opus 4.5</td><td><strong>51.9%</strong></td></tr><tr><td><strong>#58</strong></td><td>OpenHands + GPT-5</td><td><strong>43.8%</strong></td></tr></tbody></table><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><ul><li>The leaderboard has <strong>100+ entries</strong> from various agent/model combinations.</li><li>OpenHands with Claude Opus 4.5 lands in the <strong>top 50</strong>, a respectable but not dominant position.</li><li>Claude Opus 4.5 outperforms GPT-5 by <strong>+8.1 percentage points</strong> on this benchmark when paired with OpenHands.</li><li>The mid-range ranking reflects OpenHands&#39;s <strong>broader focus</strong> — it is a general-purpose coding agent, not a terminal-specific tool. Agents purpose-built for CLI interaction tend to score higher on this particular benchmark.</li></ul><h3 id="what-terminal-bench-tests" tabindex="-1">What Terminal-Bench tests <a class="header-anchor" href="#what-terminal-bench-tests" aria-label="Permalink to &quot;What Terminal-Bench tests&quot;">​</a></h3><ul><li>File system operations (create, move, search, transform files)</li><li>System administration tasks (process management, permissions, networking)</li><li>Development workflows (git operations, build systems, package management)</li><li>Shell scripting and command composition</li><li>Multi-step terminal interactions requiring state tracking</li></ul><hr><h2 id="_3-other-benchmarks-evaluation-infrastructure" tabindex="-1">3. Other Benchmarks (Evaluation Infrastructure) <a class="header-anchor" href="#_3-other-benchmarks-evaluation-infrastructure" aria-label="Permalink to &quot;3. Other Benchmarks (Evaluation Infrastructure)&quot;">​</a></h2><p>OpenHands maintains a comprehensive benchmarks repository at <a href="https://github.com/OpenHands/benchmarks" target="_blank" rel="noreferrer">github.com/OpenHands/benchmarks</a> covering:</p><table tabindex="0"><thead><tr><th>Benchmark</th><th>Focus</th><th>Status</th></tr></thead><tbody><tr><td>SWE-bench Lite</td><td>Smaller subset of SWE-bench</td><td>Active</td></tr><tr><td>SWE-bench Full</td><td>Complete SWE-bench dataset</td><td>Active</td></tr><tr><td>SWE-bench Verified</td><td>Human-validated subset</td><td>Active (headline)</td></tr><tr><td>HumanEval</td><td>Function-level code generation</td><td>Tracked</td></tr><tr><td>MBPP</td><td>Mostly Basic Python Problems</td><td>Tracked</td></tr><tr><td>Agent-specific benchmarks</td><td>Custom multi-step agent tasks</td><td>Research</td></tr></tbody></table><p>The evaluation infrastructure supports:</p><ul><li><strong>Parallel evaluation</strong> on remote runtimes (cloud-scale runs)</li><li><strong>Docker-based isolation</strong> for each benchmark instance</li><li><strong>Standardized harness</strong> for reproducible comparisons</li><li><strong>Multi-LLM sweeps</strong> to test across model providers</li></ul><hr><h2 id="_4-historical-performance-trajectory" tabindex="-1">4. Historical Performance Trajectory <a class="header-anchor" href="#_4-historical-performance-trajectory" aria-label="Permalink to &quot;4. Historical Performance Trajectory&quot;">​</a></h2><p>OpenHands (originally named OpenDevin) has shown dramatic improvement on SWE-bench over its lifetime:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>SWE-bench Performance Timeline (approximate)</span></span>
<span class="line"><span>─────────────────────────────────────────────</span></span>
<span class="line"><span>Early 2024 (OpenDevin launch)     ████████░░░░░░░░░░░░  ~25–30%</span></span>
<span class="line"><span>Mid 2024 (CodeAct v1)             ████████████░░░░░░░░  ~40–45%</span></span>
<span class="line"><span>Late 2024 (CodeAct v2 + Claude)   ████████████████░░░░  ~55–65%</span></span>
<span class="line"><span>Early 2025 (current)              ████████████████████  ~77.6%</span></span>
<span class="line"><span>─────────────────────────────────────────────</span></span></code></pre></div><h3 id="drivers-of-improvement" tabindex="-1">Drivers of improvement <a class="header-anchor" href="#drivers-of-improvement" aria-label="Permalink to &quot;Drivers of improvement&quot;">​</a></h3><ol><li><strong>LLM advances</strong> — Claude 3.5 Sonnet → Claude 4 family brought large gains.</li><li><strong>CodeAct architecture refinements</strong> — unified code action space, better tool integration, improved context management.</li><li><strong>Evaluation methodology</strong> — better prompt engineering for the benchmark harness itself.</li><li><strong>Community contributions</strong> — as one of the most active open-source agent projects, community PRs have improved edge-case handling.</li></ol><h3 id="academic-significance" tabindex="-1">Academic significance <a class="header-anchor" href="#academic-significance" aria-label="Permalink to &quot;Academic significance&quot;">​</a></h3><ul><li>OpenHands (as OpenDevin) was <strong>one of the first open-source agents</strong> to achieve competitive SWE-bench scores.</li><li>The project serves as a <strong>research baseline</strong> in many academic papers on AI coding agents.</li><li>The <strong>CodeAct paper</strong> introduced the unified code action space concept — executing code as the primary action type rather than separate tool calls.</li></ul><hr><h2 id="_5-benchmark-methodology" tabindex="-1">5. Benchmark Methodology <a class="header-anchor" href="#_5-benchmark-methodology" aria-label="Permalink to &quot;5. Benchmark Methodology&quot;">​</a></h2><h3 id="evaluation-setup" tabindex="-1">Evaluation setup <a class="header-anchor" href="#evaluation-setup" aria-label="Permalink to &quot;Evaluation setup&quot;">​</a></h3>`,39)),(t(),d(h,null,{default:n(()=>[c(r,{id:"mermaid-437",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20EH%5B%22Evaluation%20Harness%22%5D%0A%20%20%20%20%20%20%20%20I1%5B%22Instance%20(Docker)%22%5D%0A%20%20%20%20%20%20%20%20I2%5B%22Instance%20(Docker)%22%5D%0A%20%20%20%20%20%20%20%20I3%5B%22Instance%20(Docker)%22%5D%0A%20%20%20%20%20%20%20%20RS%5B%22Results%20Aggregation%20%26%20Scoring%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20I1%20--%3E%20RS%0A%20%20%20%20I2%20--%3E%20RS%0A%20%20%20%20I3%20--%3E%20RS%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<ul><li><strong>Docker sandbox</strong>: Each benchmark instance runs in an isolated container with a faithful reproduction of the target repository at the correct commit.</li><li><strong>Parallel execution</strong>: The harness supports running many instances concurrently on remote runtimes, enabling large-scale evaluation runs.</li><li><strong>Deterministic scoring</strong>: Patches are applied and the project&#39;s existing test suite determines pass/fail — no LLM-based judging.</li><li><strong>Open-source harness</strong>: The entire evaluation infrastructure is public, enabling independent reproduction of results.</li></ul><h3 id="reproducibility" tabindex="-1">Reproducibility <a class="header-anchor" href="#reproducibility" aria-label="Permalink to &quot;Reproducibility&quot;">​</a></h3><ul><li>All evaluation code is in the OpenHands benchmarks repo.</li><li>Docker images pin exact dependency versions.</li><li>Results are tracked in public Google Sheets linked from the README.</li><li>Multiple independent groups have reproduced OpenHands benchmark results.</li></ul><hr><h2 id="_6-competitive-comparison-—-swe-bench-verified" tabindex="-1">6. Competitive Comparison — SWE-bench Verified <a class="header-anchor" href="#_6-competitive-comparison-—-swe-bench-verified" aria-label="Permalink to &quot;6. Competitive Comparison — SWE-bench Verified&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>SWE-bench Verified</th><th>Open Source</th><th>Primary Model</th><th>Notes</th></tr></thead><tbody><tr><td><strong>OpenHands</strong></td><td><strong>77.6%</strong></td><td>✅ Yes</td><td>Claude</td><td>CodeAct architecture</td></tr><tr><td>SWE-agent</td><td>~30–40%</td><td>✅ Yes</td><td>Various</td><td>Princeton; CLI-focused agent</td></tr><tr><td>Aider</td><td>~40–50%</td><td>✅ Yes</td><td>Various</td><td>Editor integration focus</td></tr><tr><td>Devon</td><td>~20–30%</td><td>✅ Yes</td><td>Various</td><td>Earlier-stage project</td></tr><tr><td>Amazon Q Developer</td><td>~40–50%</td><td>❌ No</td><td>Proprietary</td><td>AWS-integrated</td></tr><tr><td>Factory Code Droid</td><td>~50–60%</td><td>❌ No</td><td>Proprietary</td><td>Enterprise-focused</td></tr></tbody></table><blockquote><p><strong>Caveats</strong>: SWE-bench scores change rapidly as both agents and models improve. Scores above are approximate mid-2025 snapshots. Proprietary agents often report on different SWE-bench variants, making direct comparison imprecise.</p></blockquote><h3 id="why-openhands-leads-among-open-source-agents" tabindex="-1">Why OpenHands leads among open-source agents <a class="header-anchor" href="#why-openhands-leads-among-open-source-agents" aria-label="Permalink to &quot;Why OpenHands leads among open-source agents&quot;">​</a></h3><ol><li><strong>CodeAct design</strong> — executing code directly rather than generating tool-call JSON reduces overhead and error modes.</li><li><strong>Docker sandbox</strong> — full environment fidelity means the agent can run tests, install dependencies, and inspect runtime behavior.</li><li><strong>Active development</strong> — large contributor community with frequent releases.</li><li><strong>Model-agnostic</strong> — can immediately leverage new frontier models.</li></ol><hr><h2 id="_7-key-benchmark-observations" tabindex="-1">7. Key Benchmark Observations <a class="header-anchor" href="#_7-key-benchmark-observations" aria-label="Permalink to &quot;7. Key Benchmark Observations&quot;">​</a></h2><h3 id="model-dependency-is-the-dominant-factor" tabindex="-1">Model dependency is the dominant factor <a class="header-anchor" href="#model-dependency-is-the-dominant-factor" aria-label="Permalink to &quot;Model dependency is the dominant factor&quot;">​</a></h3><p>The single most important variable in OpenHands benchmark performance is the underlying LLM. Switching from an open-weight model to Claude can double the SWE-bench score. This has implications for cost, latency, and deployment flexibility.</p><h3 id="codeact-is-optimized-for-coding-benchmarks" tabindex="-1">CodeAct is optimized for coding benchmarks <a class="header-anchor" href="#codeact-is-optimized-for-coding-benchmarks" aria-label="Permalink to &quot;CodeAct is optimized for coding benchmarks&quot;">​</a></h3><p>The unified code action space — where the agent writes and executes Python as its primary action type — is specifically well-suited for coding benchmarks. This is a deliberate design choice that trades generality for coding performance.</p><h3 id="docker-sandbox-enables-faithful-evaluation" tabindex="-1">Docker sandbox enables faithful evaluation <a class="header-anchor" href="#docker-sandbox-enables-faithful-evaluation" aria-label="Permalink to &quot;Docker sandbox enables faithful evaluation&quot;">​</a></h3><p>The container-based execution environment means benchmark results closely reflect real-world capability. The agent operates in the same environment a human developer would — with access to the full repo, test suite, and system tools.</p><h3 id="the-evaluation-infrastructure-is-a-product-in-itself" tabindex="-1">The evaluation infrastructure is a product in itself <a class="header-anchor" href="#the-evaluation-infrastructure-is-a-product-in-itself" aria-label="Permalink to &quot;The evaluation infrastructure is a product in itself&quot;">​</a></h3><p>OpenHands&#39;s open-source evaluation harness has become a community resource. Other agent projects use it (or fork it) for their own evaluations, which helps standardize comparison across the ecosystem.</p><h3 id="terminal-bench-reveals-specialization-gaps" tabindex="-1">Terminal-Bench reveals specialization gaps <a class="header-anchor" href="#terminal-bench-reveals-specialization-gaps" aria-label="Permalink to &quot;Terminal-Bench reveals specialization gaps&quot;">​</a></h3><p>The mid-range Terminal-Bench ranking (top 50 out of 100+) highlights that OpenHands is optimized for <strong>code editing and bug fixing</strong>, not for raw terminal interaction. Agents that are purpose-built for CLI tasks outperform it on Terminal-Bench despite scoring lower on SWE-bench.</p><hr><h2 id="_8-terminal-bench-vs-swe-bench-—-different-skills" tabindex="-1">8. Terminal-Bench vs SWE-bench — Different Skills <a class="header-anchor" href="#_8-terminal-bench-vs-swe-bench-—-different-skills" aria-label="Permalink to &quot;8. Terminal-Bench vs SWE-bench — Different Skills&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>SWE-bench</th><th>Terminal-Bench</th></tr></thead><tbody><tr><td><strong>Primary skill</strong></td><td>Bug fixing / code editing</td><td>CLI interaction</td></tr><tr><td><strong>Environment</strong></td><td>Python repos</td><td>General terminal</td></tr><tr><td><strong>Success criteria</strong></td><td>Test suite passes</td><td>Task completion</td></tr><tr><td><strong>OpenHands strength</strong></td><td>★★★★★ (77.6%)</td><td>★★★☆☆ (~52%)</td></tr><tr><td><strong>What it measures</strong></td><td>Code understanding + patching</td><td>Shell fluency + tool use</td></tr></tbody></table><p>OpenHands&#39;s architecture (CodeAct) is specifically tuned for the SWE-bench task profile. Terminal-Bench requires a different skill set — rapid shell command composition, system knowledge, and file manipulation — where OpenHands&#39;s code-execution-first approach is less advantageous.</p><hr><h2 id="_9-summary" tabindex="-1">9. Summary <a class="header-anchor" href="#_9-summary" aria-label="Permalink to &quot;9. Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Score</th><th>Ranking</th><th>Significance</th></tr></thead><tbody><tr><td>SWE-bench Verified</td><td><strong>77.6%</strong></td><td><strong>#1 open-source</strong></td><td>Headline metric; real-world bug fixing</td></tr><tr><td>Terminal-Bench 2.0 (Claude Opus 4.5)</td><td><strong>51.9%</strong></td><td><strong>#49 / 100+</strong></td><td>Mid-range; reflects broader focus</td></tr><tr><td>Terminal-Bench 2.0 (GPT-5)</td><td><strong>43.8%</strong></td><td><strong>#58 / 100+</strong></td><td>Model matters significantly</td></tr></tbody></table><p><strong>Bottom line</strong>: OpenHands is the <strong>strongest open-source coding agent on SWE-bench</strong>, with a 77.6% score that puts it in the same tier as proprietary solutions. Its Terminal-Bench performance is respectable but not exceptional, reflecting its optimization for code editing over terminal interaction. Performance is heavily model-dependent, with Claude models consistently delivering the best results.</p><hr><p><em>Last updated: 2025. Data sourced from OpenHands README badges, Terminal-Bench leaderboard, and the OpenHands benchmarks repository. Scores are approximate and subject to change as models and agents evolve.</em></p>',31))])}const S=i(p,[["render",m]]);export{y as __pageData,S as default};
